`,ColorwayTip:{title:"Wciśnij Ctrl + Alt + N aby wybrać następny motyw kolorystyczny"},compile:{label:"Kompiluj",title:"Kompiluj mapę klawiszy"},downloadFirmware:{label:"Firmware",title:"Pobierz plik firmware aby wgrać go do klawiatury"},downloadJSON:{label:"keymap.json",title:"Pobierz mapę klawiszy w formacie JSON"},downloadKeymap:{label:"Mapa klawiszy",title:"Pobierz tylko plik keymap.c"},downloadSource:{label:"Cały kod źródłowy",title:"Pobierz całość kodu QMK Firmware"},downloadToolbox:{label:"Pobierz QMK Toolbox"},errors:{invalidQMKKeymap:"Wgrany plik nie jest poprawnie sformatowaną mapą klawiszy QMK.",kbfirmwareJSONUnsupported:"Niestety Konfigurator QMK nie obsługuje wgrywania plików kbfirmware w formacie JSON",unknownJSON:"Wgrany plik nie jest mapą klawiszy QMK.",unsupportedBrowser:"Używasz przeglądarki, której nie wspieramy. Uruchom"},flashFile:{label:"Wgrywanie ręczne",title:"Wybierz plik z firmware do wgrania do klawiatury"},flashFirmware:{label:"Auto-Wgrywanie",title:"Automatyczne wgrywanie pliku firmware do klawiatury"},githubKeyboardFolder:{},help:{label:"Przywołaj czarodzieja"},importJSON:{title:"Wczytaj mapę klawiszy QMK w formacie JSON z pliku"},importUrlJSON:{title:"Wczytaj mapę klawiszy QMK w formacie JSON z adresu URL"},keyboard:{label:"Klawiatura"},keycodes:{label:"Kody klawiszy"},keycodesRef:{label:"Rozpiska kodów klawiszy"},keycodesTab:{ANSI:{label:"ANSI"},AppMediaMouse:{label:"Aplikacje, Mysz i Multimedia"},"ISO/JIS":{label:"ISO/JIS"},KeyboardSettings:{label:"Ustawienia klawiatury"},Lighting:{},Quantum:{label:"Quantum"},Steno:{}},keymap:{label:"Mapa klawiszy"},keymapHelp:{},keymapName:{label:"Nazwa mapy klawiszy",placeholder:"Własna mapa klawiszy"},layer:{confirm:"Na pewno chcesz wyczyścić aktualną warstwę?",label:"Warstwa",title:"Wyczyść warstwę"},layout:{label:"Układ"},loadDefault:{label:"Wczytaj domyślną",title:"Wczytaj domyślną mapę klawiszy z QMK Firmware"},potato:{1:"Henry Spalding pierwszy posadził ziemniaki w Idaho w 1837 roku.",2:"„Frytki” zostały pierwszy raz zaprezentowane w Ameryce, gdy Thomas Jefferson podał je podczas obiadu w Białym Domu.",3:"Amerykańcy miłośnicy zmieniaków w 2017 roku zjedli ponad 4 miliony ton frytek o przeróżnych kształtach.",4:"Zdaniem lekarza z Irlandii ziemniaki są potężnym afrodyzjakiem.",5:"Przeciętny Amerykanin w ciągu roku zjada 63,5 kilograma frytek. Prześciga go statystyczny Niemiec, którzy zjada średnio 90,7kg frytek rocznie.",6:"Według Księgi Rekordów Guinnessa największy ziemniak ważył 8,27 kg. Został on wyhodowany w Anglii w 1795 roku.",7:"Ziemniaki są na czwartym miejscu wśród najczęściej spożywanych rodzajów pożywienia - zaraz po pszenicy, kukurydzy i ryżu.",8:"Ziemniaki są uprawiane w ponad 125 krajach.",9:"Każdego roku uprawianych jest tyle ziemniaków, że ułożone w pas o szerokości 4-jezdniowej autostrady oplotły by Ziemię sześciokrotnie.",10:"Największym na świecie producentem ziemniaków są Chiny.",11:"Ziemniaki były pierwszym warzywem uprawianym w kosmosie.",12:"Ziemniaki nie zawierają glutenu.",13:"Jedną z podstawowych jednostek czasu używanych przez Inków była długość gotowania ziemniaków.",14:"Jeśli podczas uprawy ziemniak zostanie wystawiony na działanie promieni słonecznych, stanie się zielony i trujący.",15:"Potrzeba 4 ton ziemniaków aby wyprodukować 1 tonę chipsów.",16:"Obecnie znanych jest ponad 4000 różnych gatunków ziemniaków.",17:"Z punktu widzenia systematyki ziemniaki należą do małej rodziny Psiankowatych.",18:"Podczas gorączki złota Klondike na Alasce (w latach 1897-1898) 1 kilogram ziemniaków były warte niemal tyle co 1 kilogram złota.",19:"Sir Walter Raleigh sprowadził ziemniaki do do Irlandii w 1589 roku i uprawiał je nieopodal Cork na polu o powierzchni 40000 arów.",20:"Ziemniaki są dostępne przez cały rok, ponieważ przez cały rok są zbierane w różnych miejscach na świecie.",21:"Pochodzące z Afryki i Azji słodkie ziemniaki mają różne rozmiary – od malutkich aż po ważące 60 kilogramów.",22:"Narodowy Dzień Ziemniaka przypad na 19 sierpnia i 27 października.",23:"Zmieniaki wykorzystuje się do produkcji wódki, potcheen i akvavity.",24:"Ziemniaki należą do warzyw najbardziej przyjaznych środowisku. W przeciwieństwie do innych warzyw ich uprawa jest łatwa i nie wymaga dużych ilości nawozów.",25:"Ziemniaki pochodzą z regionu zajmowanego obecnie przez południową część Peru. Zostały udomowione pomiędzy 8000 a 5000 rokiem przed naszą erą.",26:"Słowo ziemniak pochodzi od staropolskiego jabłka ziemnego.",27:"Kwiaty ziemniaków są zwykle zapylane przez owady takie jak np. pszczoły.",28:"Ziemniak w 80% składa się z wody."},potatoes:"QMK do ziemniaków",print:{anonymous:{label:"Anonim"},author:{placeholder:"Wpisz swoje imię...",title:"Autor"},back:{title:"Wróć"},date:{title:"Data"},keyboard:{label:"Klawiatura"},layer:{label:"Warstwa"},layout:{label:"Układ"},notes:{empty:"Moja cudowna konfiguracja.",placeholder:"Miejsce na dodatkowe informacje dotyczące tej konfiguracji...",title:"Notatki"},print:{title:"Drukuj"},source:{title:"Źródło"}},printKeymap:{label:"Drukuj mapę",title:"Drukuj wszystkie warstwy mapy klawiszy"},settingsPanel:{advanced:{},basic:{},clearLayer:{},darkMode:{label:"Włącz/wyłącz tryb nocny"},fastInput:{help:"Autmatyczne podświetlanie kolejnego klawisza po zdefiniowaniu funkcji poprzedniego",label:"Szybkie wprowadzanie (Ctrl+Alt+F)"},help:{},input:{},language:{label:"Język"},legendType:{},legends:{},off:{label:"Wył"},on:{label:"Wł"},osKeyboardLayout:{option:{keymap_german:"Niemiecki (Niemcy i Austria)",keymap_russian:"Rosyjski",keymap_uk:"Angielski (UK)",keymap_us:"Angielski (US)"}},snowflakes:{},toggleTutorial:{help:"Przewodnik wideo MechMerlina",label:"Przewodnik wideo"}},testKeys:{label:"Test klawiatury",title:"Przetestuj działanie klawiatury"},tester:{back:{label:"Wróć",title:"Wróć do Konfiguratora"},chatter:{detectedAlert:"Wykryto wielokrotną aktywację klawisza!",label:"Próg wykrywalności dla wielokrotnej aktywacji klawisza (w ms)"},docs:{paragraph:"Uwaga: Wykryty Kod i Klawisz mogą się różnić w zależności od ustawionej lokalizacji. Dokumentacja:"},keycodeStatus:{label:"Wykryte kody klawiszy"},letters:{code:{label:"kod"},key:{label:"klawisz"},keycode:{label:"kod klawisza"}},page:{label:"Tester klawiatury"},reset:{label:"Wyczyść",title:"Zresetuj wykryte kody klawiszy"},typewritericon:{}},toggleTerminal:{}},Pj={"":{},apiVersion:"Versão da API",favoriteColor:"Cor favorita",favoriteKeyboard:"Teclado favorito",hostedOn:"Hospedado no GitHub",jobsWaiting:"Processos em execuçãoS",maintain:"Este projeto é mantido por colaboradores do QMK como você!",ready:"Pronto",serverStatus:"Status do servidor",settings:"Configurações",statsTemplate:`
