`,ColorwayTip:{title:"Ctrl + Alt + N para próximo esquema de cores"},compile:{label:"Compilar",title:"Compilar Keymap"},downloadFirmware:{label:"Firmware",title:"Baixar arquivo firmware para flashing"},downloadJSON:{label:"Keymap.JSON",title:"Exportar JSON do keymap QMK"},downloadKeymap:{label:"somente keymap",title:"Baixar somente keymap.c"},downloadSource:{label:"Full Source",title:"Download QMK Firmware code"},downloadToolbox:{label:"Requerir QMK Toolbox"},errors:{invalidQMKKeymap:"Desculpe, este não parece ser um arquivo de mapa de chaves do QMK válido.",kbfirmwareJSONUnsupported:"Desculpe, o QMK Configurator não suporta a importação de arquivos JSON do kbfimware.",unknownJSON:"Desculpe, este não parece ser um arquivo de mapa de teclas do QMK.",unsupportedBrowser:"Você está usando um navegador não suportado. Por favor, use"},flashFile:{label:"Flash-Customizado",title:"Enviar arquivo selecionado pelo usuário para o MCU"},flashFirmware:{label:"Auto-Flash",title:"Enviar firmware para MCU automaticamente"},githubKeyboardFolder:{},help:{label:"Invocar mago"},importJSON:{title:"Importar JSON do keymap QMK"},importUrlJSON:{title:"Importar JSON da URL QMK Keymap JSON"},keyboard:{label:"teclado"},keycodes:{label:"Keycodes"},keycodesRef:{label:"Referencias de Keycodes"},keycodesTab:{ANSI:{label:"ANSI"},AppMediaMouse:{label:"App, Midia e Mouse"},"ISO/JIS":{label:"ISO/JIS"},KeyboardSettings:{label:"Configurações de teclado"},Lighting:{},Quantum:{label:"Quantum"},Steno:{}},keymap:{label:"Keymap"},keymapHelp:{},keymapName:{label:"Nome da keymap",placeholder:"nome da keymap customizada"},layer:{confirm:"Limpar as camadas”",label:"Camadas",title:"Limpar camadas"},layout:{label:"layout"},loadDefault:{label:"Carregar padrão",title:"Carregar keymap padrão do QMK Firmware"},potato:{1:"Henry Spalding plantou batatas em Idaho pela primeira vez em 1837.",2:'"Batatas fritas" foram introduzidas na América quando Thomas Jefferson as serviu em um jantar na Casa Branca.',3:"Os americanos amantes de batata consumiram mais de 4 milhões de toneladas de batatas fritas em várias formas e tamanhos em 2017.",4:"Batata é um poderoso afrodisíaco, diz médico na Irlanda.",5:"O americano consome em média 140 libras de batatas por ano. No entanto, os alemães comem mais de 200 libras por ano.",6:"A maior batata cultivada foi na Inglaterra em 1795 custando 18 libras e 4 onças de acordo com o Guinness Book of World Records (O livro dos recordes).",7:"A batata é o quarto alimento básico do mundo - depois do trigo, milho e arroz.",8:"Batatas são cultivadas em mais de 125 países.",9:"Todos os anos são cultivadas em todo o mundo o suficiente de batatas para cobrir uma rodovia de quatro faixas que circula o mundo seis vezes.",10:"A China é o maior produtor mundial de batata.",11:"As batatas foram o primeiro vegetal cultivado no espaço.",12:"Batatas são totalmente sem glúten.",13:"Uma das medidas mais básica do tempo da Civilização Inca era o tempo necessário para cozinhar uma batata.",14:"Se uma batata for exposta à luz durante o crescimento, ela ficará verde e se tornaná venenosa.",15:"São necessários 10000 libras de batatas para produzir 2500 libras de batatas fritas.",16:"Hoje existem mais de 4000 tipos diferentes de batatas.",17:"As batatas pertencem a uma família pequena chamada Nightshade ou Solanaceae.",18:"Durante a corrida do ouro de Klondike (1897-1898) no Alasca, as batatas praticamente valiam seu peso em ouro.",19:"Sr Walter Raleigh introduziu batatas na Irlanda em 1589 nos 40000 acres de terra perto de Cork.",20:"As batatas estão disponíveis durante todo o ano, pois são colhidas em algum lugar todos os meses do ano.",21:"Nativo da África e da Ásia, o tamanho do inhame varia do tamanho de uma batata pequena até o tamanho recorde de 130 libras.",22:"19 de Agosto e 27 de Outubro são comemorados como Dia Nacional da Batata.",23:"As batatas também são usadas para preparar bebidas alcoólicas como vodka, potcheen ou akvavit.",24:"As batatas estão entre os vegetais mais ecológicos, pois são fáceis de cultivas e não exigem grandes quantidades de fertilizantes e aditivos químicos para prosperar, como muitos outros vegetais.",25:"A batata teve origem na região do sul do Peru, onde foi domesticada pela primeira vez entre 8000 a.C. e 5000 a.C.",26:'A palavra "batata" vem da palavra em espanhol "patata".',27:"As plantas de batata são geralmente polinizadas por insetos como abelhas.",28:"Uma batata tem cerca de 80% de água e 20% de sólidos."},potatoes:"QMK para batatas",print:{anonymous:{label:"Anônimo"},author:{placeholder:"Seu nome (opcional)",title:"Autor"},back:{title:"Voltar"},date:{title:"Data"},keyboard:{label:"Teclado"},layer:{label:"Camada"},layout:{label:"Layout"},notes:{empty:"Meu mapa de teclado impressionante",placeholder:"Anotações sobre esta configuração",title:"Anotações"},print:{title:"Impressão"},source:{title:"Fonte"}},printKeymap:{label:"Printar Keymap",title:"Printar camadas de Keymap"},settingsPanel:{advanced:{},basic:{},clearLayer:{},darkMode:{},fastInput:{help:"Entrada de comandos a partir do teclado sem clicar em outra posição",label:"Entrada rápida (Ctrl+Alt+F)"},help:{},input:{},language:{label:"Linguagem"},legendType:{},legends:{},off:{label:"Off"},on:{label:"On"},osKeyboardLayout:{option:{keymap_german:"Alemão (Alemanha e Áustria)",keymap_russian:"Russo",keymap_uk:"Inglês (Reino Unido)",keymap_us:"Inglês (EUA)"}},snowflakes:{},toggleTutorial:{help:"MechMerlin video guide",label:"Tutorial em Video"}},testKeys:{label:"Testar teclado",title:"Testar entrada do teclado"},tester:{back:{label:"Back",title:"Return to Configurator"},chatter:{detectedAlert:"chatter has been detected!",label:"Chatter threshold (ms)"},docs:{paragraph:"Note: Detected Key and Code may differ depending on your locale. Docs"},keycodeStatus:{label:"Keycodes Detected"},letters:{code:{label:"code"},key:{label:"key"},keycode:{label:"keycode"}},page:{label:"Keyboard Tester"},reset:{label:"Reset",title:"Reset detected keys"},typewritericon:{}},toggleTerminal:{}},wj={"":{},apiVersion:"Версия API",apiVersionPrefix:"API",favoriteColor:"Избранная расцветка",favoriteKeyboard:"Избранная клавиатура",hostedOn:"Размещено на GitHub Pages",jobsAhead:"в работе",jobsWaiting:"ожидают",maintain:"Данный проект поддерживается коллабораторами QMK и такими же участниками, как вы!",ready:"Готово",searchKeycodes:"Поиск",serverIs:"Сервис",serverStatus:"Статус сервера",settings:"Настройки",statsTemplate:`
